<?php // cron/auto_update.php // This script runs automatically to update blog statistics require_once '../database.php'; $database = new Database(); $conn = $database->getConnection(); // Update category post counts $updateSql = "UPDATE blog_categories c SET post_count = ( SELECT COUNT(*) FROM blog_posts p WHERE p.category = c.slug AND p.status = 'published' )"; $conn->exec($updateSql); // Update popular posts $popularSql = "SELECT id, title, views FROM blog_posts WHERE status = 'published' ORDER BY views DESC LIMIT 10"; // Send email notification for popular posts $stmt = $conn->prepare($popularSql); $stmt->execute; $popularPosts = $stmt->fetchAll(); if (!empty($popularPosts)) { $message = "Weekly Blog Stats:\n\n"; foreach ($popularPosts as $post) { $message.= "- {$post['title']}: {$post['views']} views\n"; } // Send email (configure mail settings in Hostinger) mail('your-email@example.com', 'Weekly Blog Stats', $message); } echo "Blog auto-update completed at ". date('Y-m-d H:i:s');?>

